{% stylesheet %}
  .card {
    display: flex;
    font-size: 0.8rem;
    gap: 0.5rem;
    border: 1px solid lightgrey;
    padding: 0.5rem;
    border-radius: 0.25rem;
    text-decoration: none;
    color: black;
  }
  .card:hover {
    background-color: lightgrey;
  }
  .card:hover .card__title {
    text-decoration: underline;
  }
  .card__image {
  }
  .card__content {
    flex: 2;
  }
  .card__title {
    font-size: 0.8rem;
  }
  .grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(25rem, 1fr));
    gap: 0.5rem;
    margin: 0.5rem;
  }
{% endstylesheet %}

{% if section.blocks.size > 0 %}
  <h1 class="sticky-header">
    All Categories >
    {{ section.settings.collection.title }} ({{ section.blocks.size }}
    {{ section.blocks.size | pluralize: 'category', 'categories' }})
  </h1>
{% endif %}

{% if section.blocks.size > 0 %}
  <div class="grid">
    {%- for block in section.blocks -%}
      {% for child in block.settings.next_children %}
        <link rel="preload" as="image" href="{{ child.image | image_url: width: 150 }}">
      {% endfor %}
      <a href="{{ block.settings.link }}" class="card prefetch">
        <div class="card__image">
          {{ block.settings.image | image_url: width: 150 | image_tag: alt: block.settings.title }}
        </div>
        <div class="card__content">
          <div class="card__title">{{ block.settings.title | split: ' > ' | last }}</div>
          <div class="card__description">{{ block.settings.description }}</div>
        </div>
      </a>
    {%- endfor -%}
  </div>
{% endif %}

{% schema %}
{
  "name": "Category Multicolumn",
  "class": "section",
  "tag": "section",
  "disabled_on": {
    "groups": ["header", "footer"]
  },
  "settings": [
    {
      "type": "collection",
      "id": "collection",
      "label": "Collection"
    }
  ],
  "blocks": [
    {
      "type": "column",
      "name": "Column",
      "settings": [
        {
          "type": "image_picker",
          "id": "image",
          "label": "t:sections.multicolumn.blocks.column.settings.image.label"
        },
        {
          "type": "inline_richtext",
          "id": "title",
          "label": "t:sections.multicolumn.blocks.column.settings.title.label"
        },
        {
          "type": "richtext",
          "id": "description",
          "label": "description text"
        },
        {
          "type": "metaobject_list",
          "id": "next_children",
          "metaobject_type": "category_metaobject",
          "label": "next children"
        },
        {
          "type": "url",
          "id": "link",
          "label": "link url"
        }
      ]
    }
  ]
}
{% endschema %}

{% paginate search.results by 24 %}
  {% for product in search.results %}
    {% comment %}
      Every product is in multiple auto collections that look like this: ["building consumables", "building consumables > solder & flux", "building consumables > solder & flux > rosin flux"]
      So we search for the _longest handle_ to find the leaf category of the product and link to that.
    {% endcomment %}
    {% assign collection_with_longest_handle = product.collections | sort: 'handle.size' | last %}
    {% assign modified_handle = collection_with_longest_handle.handle | remove_first: 'hardware-' %}
    <div>
      <img src="{{ product.featured_image | image_url }}" height="100px" alt="{{ product.title }}">
      <a href="/pages/category/{{ modified_handle }}#{{ product.handle }}">
        {{ product.title }}
      </a>
    </div>
  {% endfor %}
{% endpaginate %}

{% assign collection_products = section.settings.collection.products %}
{% if collection_products.size > 0 %}
  <h1 class="sticky-header">
    All Categories >
    {{ section.settings.collection.title }} ({{ collection_products.size }}
    {{ collection_products.size | pluralize: 'product', 'products' }})
  </h1>

  <div class="product-collection" style="font-family: Arial, sans-serif;">
    {% for product in collection_products %}
      <div class="product-container">
        <span id="{{ product.handle }}" class="hash-handle"></span>
        <h3 class="product-title">{{ product.title }}</h3>
        <p class="product-description">{{ product.description | strip_html | truncatewords: 30 }}</p>

        <div class="product-details">
          <div class="image-placeholder">
            {% if product.featured_image %}
              {{ product.featured_image | image_url: width: 100 | image_tag: alt: product.featured_image.alt }}
            {% endif %}
          </div>
          <table class="variant-table">
            <thead>
              <tr>
                <th class="desktop-only">SKU</th>
                <th class="desktop-only">{{ product.options[0] }}</th>
                {% if product.options[1] %}
                  <th class="desktop-only">{{ product.options[1] }}</th>
                {% endif %}
                <th>Model</th>
                <th class="desktop-only">Net Weight</th>
                <th>Each</th>
                <th>Buy</th>
              </tr>
            </thead>
            <tbody>
              {% for variant in product.variants %}
                <tr class="variant-row">
                  <td class="desktop-only">{{ variant.sku }}</td>
                  <td class="desktop-only">{{ variant.option1 }}</td>
                  {% if variant.option2 %}
                    <td class="desktop-only">{{ variant.option2 }}</td>
                  {% endif %}
                  <td>{{ variant.title }}</td>
                  <td class="desktop-only">{{ variant.weight | default: 'N/A' }}g</td>

                  <td>{{ variant.price | money }}</td>
                  <td>
                    <form class="add-to-cart-form" method="post" action="/cart/add">
                      <input type="hidden" name="id" value="{{ variant.id }}">
                      <input min="1" type="number" id="quantity" name="quantity" value="1">
                      <input type="submit" value="Add to cart" class="add-button">
                      <input type="submit" value="Added!" class="added-button" disabled>
                    </form>
                  </td>
                </tr>
              {% endfor %}
            </tbody>
          </table>
        </div>
      </div>
    {% endfor %}
  </div>
{% endif %}

{% stylesheet %}
  .desktop-only {
    display: none;
  }
  @media (min-width: 768px) {
    .desktop-only {
      display: table-cell;
    }
  }
  .product-collection {
    font-family: Arial, sans-serif;
  }
  .collection-title {
    font-size: 24px;
    margin-bottom: 10px;
  }
  .product-count {
    font-size: 14px;
    margin-bottom: 20px;
  }
  .product-container {
    margin-bottom: 20px;
    padding: 10px;
    position: relative;
  }
  .hash-handle {
    visibility: hidden;
    top: -35px;
    position: absolute;
  }
  .product-title {
    font-size: 18px;
    color: green;
  }
  .product-description {
    font-size: 12px;
  }
  .product-details {
    display: flex;
    align-items: center;
    margin-bottom: 10px;
  }
  .image-placeholder {
    width: 100px;
    height: 100px;
    margin-right: 10px;
  }
  .image-placeholder img {
    width: 100%;
    height: auto;
    object-fit: cover;
  }
  .variant-table {
    width: 100%;
    border-collapse: collapse;
  }
  th,
  td {
    text-align: left; /* Left-align headers and cells */
    padding: 4px; /* Tighter line height */
    font-size: 12px;
  }
  .variant-row:hover {
    background-color: #fff5b1; /* Pale yellow background on hover */
  }

  .add-to-cart-form input[type='number'] {
    width: 2rem;
  }

  .added-button {
    display: none;
  }
{% endstylesheet %}

{% javascript %}
  document.addEventListener('DOMContentLoaded', function () {
    // Dynamically add items to the cart without reloading the page
    document.querySelectorAll('.add-to-cart-form').forEach((form) => {
      form.addEventListener('submit', function (event) {
        event.preventDefault();

        const formData = new FormData(form);

        fetch(window.Shopify.routes.root + 'cart/add.js', {
          method: 'POST',
          body: formData,
        })
          .then((response) => response.json())
          .then((data) => {
            form.querySelector('.add-button').style.display = 'none';
            form.querySelector('.added-button').style.display = 'inline-block';
            setTimeout(() => {
              form.querySelector('.added-button').style.display = 'none';
              form.querySelector('.add-button').style.display = 'inline-block';
            }, 2000);
            // Update the cart item count in the page header
            fetch(window.Shopify.routes.root + 'cart.js', {
              method: 'GET',
            })
              .then((response) => response.json())
              .then((cart) => {
                document.querySelector('#cart-item-count').textContent = cart.items.length;
              });
          })
          .catch((error) => {
            console.error('Error adding item to cart:', error);
          });
      });
    });
  });
{% endjavascript %}

{% schema %}
{
  "name": "Single Collection View",
  "class": "section",
  "tag": "section",
  "disabled_on": {
    "groups": ["header", "footer"]
  },
  "settings": [
    {
      "type": "collection",
      "id": "collection",
      "label": "Collection"
    }
  ]
}
{% endschema %}

{% unless shop.enabled_payment_types == empty %}
  <ul 
    class="payment-icons"
    aria-label="{{ 'general.accessibility.payment_methods' | t }}">
    {% for type in shop.enabled_payment_types %}
      <li 
        class="" 
        data-bs-toggle="tooltip" 
        data-bs-placement="top" 
        title="{{ type | replace: "_", " " | camelcase }}">
        {{ type | payment_type_svg_tag: class: 'icon' }}
      </li>
    {% endfor %}
  </ul>
  <small class="payment-icons-text">
    {{ 'general.payment_icons.secure' | t }}
  </small>
{% endunless %}

{% liquid 
  assign pt = block.settings.pt | prepend: 'pt-'
  assign pb = block.settings.pb | prepend: 'pb-'
%}

<div 
  class="product-block-richtext {{ pt }} {{ pb }}" 
  {{ block.shopify_attributes }}>
  {% unless block.settings.title == blank %}
    <h2 class="title {{ block.settings.title_font_size }}">
      {{ block.settings.title }}
    </h2>
  {% endunless %}
  {% if block.settings.description != blank or block.settings.product_description != false %}
    <div class="description rte mb-0 {{ block.settings.description_font_size }} {{ block.settings.description_classes }}">
      {{ block.settings.description }}
      {% if block.settings.product_description %}
        {{ product.description }}
      {% endif %}
    </div>
  {% endif %}
</div>

{% liquid 
  assign metafield_namespace = settings.product_custom_badge_metafield | split: '.' | first
  assign metafield_key = settings.product_custom_badge_metafield | split: '.' | last
  assign metafield = product.metafields[metafield_namespace][metafield_key]

  assign text = metafield | split: '|' | first
  assign color = metafield | split: '|' | last 
%}

{% if metafield != blank %}
  <span 
    class="product-custom-badge badge {{ settings.product_custom_badge_bg_color }}"
    style="{% if color != blank %}background: {{ color }} !important{% endif %}">
    {% if color != blank %}
      <span style="border-bottom-color: {{ color | strip | color_darken: 15 }}"></span>
    {% endif %}
    {{ text }}
  </span>
{% endif %}

{% comment %}
  Renders a header (title and description) that is usually the same accross sections

  Accepts:
  - class: {String} (Optional) An optional class (or classes) to apply to header element

  Usage:
  {% render 'section-header' %}
{% endcomment %}

{% if section.settings.header_title != blank or section.settings.header_description != blank %}
  <header class="section-header text-center {{ class }}">
    {% unless section.settings.header_title == blank %}
      <h2 class="title {{ section.settings.header_title_font_size }}">
        {{ section.settings.header_title }}
      </h2>
    {% endunless %}
    {% unless section.settings.header_description == blank %}
      <div class="description rte opacity-70 {{ section.settings.header_description_font_size }}">
        {{ section.settings.header_description }}
      </div>
    {% endunless %}
  </header>
{% endif %}

{% comment %} 
  Loox
{% endcomment %}
<div class="loox-rating" data-id="{{ product.id }}" data-rating="{{ product.metafields.loox.avg_rating }}" data-raters="{{ product.metafields.loox.num_reviews }}"></div>

{% comment %} 
  JudgeMe
{% endcomment %}
<div style="{{ jm_style }}" class="jdgm-widget jdgm-preview-badge"  data-id="{{ product.id }}">{{ product.metafields.judgeme.badge }}</div>

{% comment %}
  Renders the price paragraph for the product card, but it may be used on other parts when
  there is a product list

  Accepts:
  - product: {object} The product object

  Usage:
  {% render 'product-card-price' product: product  %}
{% endcomment %}

<p class="product-card-price product-price mb-4">
  {% if product.compare_at_price > product.price %}
    <s class="product-card-price-compare">
      <span class="visually-hidden">
        {{ 'product.regular_price' | t }} 
      </span>
      {{ product.compare_at_price | money_without_trailing_zeros }}
    </s>
    <span class="product-card-price-final product-price-final-sale">
      <span class="visually-hidden">
        {{ 'product.sale_price' | t }} 
      </span>
      {{ product.price | money_without_trailing_zeros }}
    </span>
  {% else %}
    <span class="product-card-price-final">
      {{ product.price | money_without_trailing_zeros }}
    </span>
  {% endif %}
</p>

{% case block.type %}
  {% when 'richtext' %}
    {% unless block.settings.description == blank %}
      <div class="description rte mt-2 mb-6">
        {{ block.settings.description }}
      </div>
    {% endunless %}
    {% unless block.settings.btn_primary_text == blank %}
      <div class="m-n2">
        {% unless block.settings.btn_primary_text == blank %}
          <a 
            class="btn btn-sm m-2 {{ block.settings.btn_primary_color }}" 
            href="{{ block.settings.btn_primary_url }}">
            {{ block.settings.btn_primary_text }}
          </a>
        {% endunless %}
        {% unless block.settings.btn_secondary_text == blank %}
          <a 
            class="btn btn-sm m-2 {{ block.settings.btn_secondary_color }}" 
            href="{{ block.settings.btn_secondary_url }}">
            {{ block.settings.btn_secondary_text }}
          </a>
        {% endunless %}
      </div>
    {% endunless %}
  {% when 'menu' %}
    <ul 
      class="nav flex-column mb-0" 
      aria-label="{{ block.settings.title }}">
      {% for link in linklists[block.settings.menu].links %}
        <li class="nav-item">
          <a 
            class="nav-link px-0 px-desktop-3 py-3 py-desktop-2" 
            href="{{ link.url }}">
            {{ link.title }}
          </a>
        </li>
      {% endfor %}
    </ul>
{% endcase %}

{% comment %}
  Renders a collection card within a collection list. Usually within a collection template or the Featured Collections section

  Accepts:
  - collection: {object} The collection object - https://shopify.dev/docs/api/liquid/objects/collection
  - block: {object} (Optional) The section block, if rendered within the Featured Collections section.

  Usage:
  {% render 'collection-card' collection: collection, block: block  %}
{% endcomment %}

{% liquid 
  assign img = block.settings.img | default: collection.image
  assign title = block.settings.title | default: collection.title
%}

<div class="collection-card {{ section.settings.collection_card_text_align }}">
  <a 
    href="{{ collection.url }}" 
    class="collection-card-link">
    <div class="collection-card-img-wrapper">
      {% render 'image-url', img: img, size: 900, orientation: section.settings.collection_card_img_orientation, class: section.settings.collection_card_img_border %}
      {% if section.settings.collection_card_show_title %}
        <h3 
          class="
            collection-card-title collection-title mb-0 
            {{ section.settings.collection_card_title_font_size }}
            {{ section.settings.collection_card_title_position }}
          ">
          {{ title }} 
          {% if section.settings.collection_card_show_product_count %}
            ({{ collection.products_count }})
          {% endif %}
        </h3>
      {% endif %}
    </div>
  </a>
</div>

{% comment %}
  Renders an "Add to cart" button or a "Quick view" button if the product has multiple variants
  Usually it is used with the product card

  Accepts:
  - product: {object} The product object
  - btn_color {string} (Optional) The button color class (bootstrap) to apply to the button

  Usage:
  {% render 'product-card-form' product: product  %}
{% endcomment %}

{% liquid 
  assign btn_color = btn_color | default: settings.product_card_atc_btn_color
%}

<product-form>
  {% form 'product', product, data-productid: product.id %}
    {% if product.has_only_default_variant %}
      <input type="hidden" name="id" data-productid="{{ product.id }}" value="{{ product.first_available_variant.id }}">
    {% else %}
      <select 
        class="form-select form-select-sm mb-3"
        name="id" 
        aria-label="{{ 'product.select_variant' | t }}">
        {% for variant in product.variants %}
          <option value="{{ variant.id }}" {% unless variant.available %}disabled{% endunless %}>
            {{ variant.title }} - {{ variant.price | money_without_trailing_zeros }}
          </option>
        {% endfor %}
      </select>
    {% endif %}
    <button
      class="btn btn-atc btn-sm {{ btn_color }}"
      type="submit"
      name="add"
      {% unless product.available %}disabled{% endunless %}>
      {% if product.available %}
        {{ 'product.add_to_cart' | t }}
      {% else %}
        {{ 'product.sold_out' | t }}
      {% endif %}
    </button>
  {% endform %}
</product-form>

{% if cart.items != empty %}
  <div class="offcanvas-footer pt-5">
    {% if cart.cart_level_discount_applications.size > 0 %}
      <ul 
        class="cart-discounts list-unstyled fs-xs mb-3 text-center alert alert-primary py-2 px-2" 
        aria-label="{{ 'cart.applied_discounts' | t }}">
        {% for discount in cart.cart_level_discount_applications %}
          <li class="">
            {% render 'svg-icons', icon: 'tag', size: 12, class: 'me-1' %}
            {{ discount.title }}
            (-{{ discount.total_allocated_amount | money }})
          </li>
        {% endfor %}
      </ul>
    {%- endif -%}
    <p class="cart-subtotal fs-5 mb-4" role="status">
      <span class="opacity-70 me-2">
        {{ 'cart.subtotal' | t }}: 
      </span>
      <span>
        {% if cart.items_subtotal_price > cart.total_price %}
          <s class="opacity-70 me-2">
            {{ cart.items_subtotal_price | money }}
          </s>
        {% endif %}
        <b>
          {{ cart.total_price | money }}
        </b>
      </span>
    </p>
    {% form 'cart', cart %}
      <button 
        class="btn btn-checkout btn-primary btn-lg" 
        name="checkout" 
        type="submit"
        onclick="this.classList.add('loading')">
        {% render 'svg-icons', icon: 'lock', size: 18, class: 'me-4' %}
        {{ 'cart.checkout' | t }}
      </button>
    {% endform %}
    <p class="small text-center mt-3 mb-n2 fst-italic">
      {{ 'cart.taxes_shipping_at_checkout_html' | t }}
    </p>
  </div>
{% endif %}

{% comment %}
  Renders an article card within a article list. Usually within a blog template or the Article list section

  Accepts:
  - article: {object} The article object - https://shopify.dev/docs/api/liquid/objects/article

  Usage:
  {% render 'article-card' article: article  %}
{% endcomment %}

<div class="article-card {{ section.settings.article_card_text_align }}">
  <a 
    href="{{ article.url }}" 
    class="article-card-link">
    <div class="article-card-img-wrapper position-relative mb-4">
      {% if section.settings.article_card_tags %}
        <ul 
          class="article-card-tags list-unstyled d-flex m-4" 
          aria-label="{{ 'general.blog.posted_in' | t }}">
          {% for tag in article.tags %}
            <span class="article-card-tag badge bg-primary m-1">
              {{ tag }}
            </span>  
          {% endfor %}
        </ul>
      {% endif %}
      {% render 'image-url', img: article.image, orientation: section.settings.article_card_img_orientation, class: section.settings.article_card_img_border %}
    </div>
    <h3 class="article-card-title mb-0 {{ section.settings.article_card_title_size }}">
      {{ article.title }}
    </h3>
    {% if section.settings.article_card_meta %}
      <p class="article-card-meta opacity-70 mt-2 mb-0 small">
          {{ article.author }} @ {{ article.created_at | time_tag: '%b %d, %Y' }}
      </p>
    {% endif %}
    {% if section.settings.article_card_excerpt and article.excerpt != blank %}
      <div class="article-card-excerpt rte small mt-3">
        {{ article.excerpt }}
      </div>
    {% endif %}
  </a>
</div>

{% liquid 
  assign current_variant = product.selected_or_first_available_variant

  assign pt = block.settings.pt | prepend: 'pt-'
  assign pb = block.settings.pb | prepend: 'pb-'
%}

<div 
  class="product-price {{ block.settings.font_size }} {{ pt }} {{ pb }}"
  {{ block.shopify_attributes }}>

  <div class="d-flex align-items-center">

    <s 
      class="product-price-compare" 
      {% unless current_variant.compare_at_price > current_variant.price %}hidden{% endunless %}>
      <span class="visually-hidden">
        {{ 'product.regular_price' | t }} 
      </span>
      {{ current_variant.compare_at_price | money_without_trailing_zeros }}
    </s>

    <span class="product-price-final {% if current_variant.compare_at_price > current_variant.price %}product-price-final-sale{% endif %}">
      {% if current_variant.compare_at_price > current_variant.price %}
        <span class="visually-hidden">
          {{ 'product.sale_price' | t }} 
        </span>
      {% endif %}
      {{ current_variant.price | money_without_trailing_zeros }}
    </span>

    <span 
      class="product-sale-badge badge" 
      data-discount-type="{{ block.settings.badge_discount_type }}"
      {% unless current_variant.compare_at_price > current_variant.price %}hidden{% endunless %}>
      {{ 'product.save' | t }}
      {% if current_variant.compare_at_price > 0 %}
        {% if block.settings.badge_discount_type == 'percentage' %} 
          {{ current_variant.compare_at_price | minus: current_variant.price | times: 100 | divided_by: current_variant.compare_at_price | round | append: '%' }}
        {% else %}
          {{ current_variant.compare_at_price | minus: current_variant.price | money_without_trailing_zeros }}
        {% endif %}
      {% endif %}
    </span> 

    <span 
      class="product-sold-out-badge badge"
      {% if current_variant.available %}hidden{% endif %}>
      {{ 'product.sold_out' | t }}
    </span>    
  </div>

</div>

{{ form | payment_terms }}

{% liquid 
  assign pt = block.settings.pt | prepend: 'pt-'
  assign pb = block.settings.pb | prepend: 'pb-'
%}

{% unless product.has_only_default_variant %}
  <ul 
    class="product-options list-unstyled mb-0 {{ pt }} {{ pb }}"
    aria-label="{{ 'product.product_options' | t }}">
    {% for option in product.options_with_values %}
      <li class="py-3">
        {% if block.settings.options_style == 'buttons' %}       
          <p class="mb-1">
            {{ option.name }}
          </p>
          <ul class="size-buttons list-unstyled">
            {% for value in option.values %}
              <li>
                <input 
                  class="visually-hidden" 
                  type="radio" 
                  name="option-{{ option.name | handleize }}" 
                  id="option-{{ option.name | handleize }}-{{ value | handleize }}" 
                  value="{{ value | escape }}"
                  {% if option.selected_value == value %}checked{% endif %}>
                <label for="option-{{ option.name | handleize }}-{{ value | handleize }}">
                  {{ value }}
                </label>
              </li>
            {% endfor %}
          </ul>
        {% else %}
          <label class="form-label" for="option-{{ option.name | handleize }}">
            {{ option.name }}
          </label>
          <select
            id="option-{{ option.name | handleize }}"
            name="option-{{ option.name | handleize }}"
            class="form-select">
            {% for value in option.values %}
              <option 
                value="{{ value | escape }}" {% if value == option.selected_value %}selected{% endif %}>
                {{ value }}
              </option>
            {% endfor %}
          </select>
        {% endif %}
      </li>
    {% endfor %}
  </ul>
{% endunless %}

{% comment %}
  Renders a product card within a product list. Usually within a collection template or the Product list section

  Accepts:
  - product: {object} The product object - https://shopify.dev/docs/api/liquid/objects/product

  Usage:
  {% render 'product-card' product: product  %}
{% endcomment %}

<div class="product-card {{ settings.product_card_text_align }}">
  <a 
    href="{{ product.url | within: collection }}" 
    class="product-card-link">
    <div class="product-card-img-wrapper mb-4">      
      {% if product.available == false %}
        <span class="product-sold-out-badge badge"
          {% if current_variant.available %}hidden{% endif %}>
          {{ 'product.sold_out' | t }}
        </span>  
      {% elsif product.compare_at_price > product.price %}
        <span 
          class="product-sale-badge badge"
          data-discount-type="{{ settings.product_card_badge_discount_type }}"> 
          {% if product.compare_at_price > 0 %}
            {% if settings.product_card_badge_discount_type == 'percentage' %} 
              <span class="visually-hidden">
                {{ 'product.save' | t }} 
              </span>
              {{ product.compare_at_price | minus: product.price | times: 100 | divided_by: product.compare_at_price | round | prepend: '-' | append: '%' }}
            {% else %}
              {{ 'product.save' | t }} 
              {{ product.compare_at_price | minus: product.price | money_without_trailing_zeros }}
            {% endif %}
          {% endif %}
        </span>
      {% endif %}
      {% render 'image-url', img: product.featured_image, orientation: settings.product_card_img_orientation, class: settings.product_card_img_border %}
    </div>
    <h3 class="product-card-title product-title {{ settings.product_card_title_font_size }}">
      {{ product.title }}
    </h3>
    {% render 'product-rating-badge', product: product %}
    {% render 'product-card-price', product: product %}
  </a>
  {% if settings.product_card_show_atc_form %}
    {% render 'product-card-form', product: product %}
  {% endif %}
</div>

{% liquid 
  assign pt = block.settings.pt | prepend: 'pt-'
  assign pb = block.settings.pb | prepend: 'pb-'
%}

<div 
  class="product-block-collapse {{ pt }} {{ pb }}" 
  {{ block.shopify_attributes }}>
  <div 
    class="
      collapse-wrapper
      {{ block.settings.border_top_width | prepend: 'border-top-' }}
      {{ block.settings.border_bottom_width | prepend: 'border-bottom-' }}
      {{ block.settings.border_color }} 
    "
    style="
      border-top-style: solid;
      border-bottom-style: solid;
      --bs-border-opacity: {{ block.settings.border_opacity | append: '%' }};
    ">
    <button 
      class="
        {{ block.settings.title_font_family }}
        {{ block.settings.title_font_size }} 
        {{ block.settings.title_text_transform }} 
        {{ block.settings.title_letter_spacing | prepend: 'ls-' }} 
      " 
      type="button" 
      data-bs-toggle="collapse" 
      data-bs-target="#collapse-{{ block.id }}" 
      aria-expanded="{% if block.settings.open_by_default %}true{% else %}false{% endif %}" 
      aria-controls="collapse-{{ block.id }}">
      <div class="d-flex align-items-center">
        {% unless block.settings.icon == blank %}
          <img 
            class="img-fluid me-5"
            src="{{ block.settings.icon | image_url: width: block.settings.icon_size }}" 
            alt="{{ block.settings.icon.alt }}"
            width="{{ block.settings.icon_size }}"
            height="{{ block.settings.icon_size | divided_by: block.settings.icon.aspect_ratio | round }}"
            loading="lazy">
        {% endunless %}
        {{ block.settings.title }}
      </div>
      {% render 'svg-icons', icon: 'chevron-down', size: 18 %}
    </button>
    <div id="collapse-{{ block.id }}" class="collapse {% if block.settings.open_by_default %}show{% endif %}">
      <div class="collapse-inner description rte mb-0 {{ block.settings.description_font_size }}">
        {% if block.settings.description contains '[page' %}
          {% assign page_handle = block.settings.description | split: '[page:' | last | split: ']' | first %}
          {{ pages[page_handle].content }}
        {% elsif block.settings.product_description %}
          {{ product.description }}
        {% else %}
          {{ block.settings.description }}
        {% endif %}
      </div>
    </div>
  </div>
</div>

{% liquid 
  assign block = section.blocks | where: 'type', 'media_gallery' | first

  assign current_variant = product.selected_or_first_available_variant

  if current_variant.featured_image
    assign initial_slide = product.selected_or_first_available_variant.featured_media.position | minus: 1
  else
    assign initial_slide = 0
  endif
%}

{% if product == nil %}
  {{ 'image' | placeholder_svg_tag: 'img-thumbnail' }}
{% elsif block != nil %}
  <product-media-gallery
    class="product-media-gallery"
    data-product-id="{{ product.id }}"
    data-initial-slide="{{ initial_slide }}"
    data-speed="{{ block.settings.speed }}"
    data-thumbs-per-view="{{ block.settings.thumbs_per_view }}">
    <div class="swiper-main-wrapper {{ block.settings.img_border }}">
      <div 
        class="swiper-main swiper"
        style="--swiper-theme-color: {{ block.settings.controls_color | prepend: 'var(--bs-' | append: '-rgb)' }}">
        <div class="swiper-wrapper">
          {% for media in product.media %}
            {% liquid 
              assign media_loading = 'eager' 
              if forloop.index > 2
                assign media_loading = 'lazy' 
              endif
            %}
            <div class="swiper-slide" lazy="{% if media_loading == 'lazy' %}true{% endif %}">
              {% case media.media_type %}
                {% when 'image' %}
                  {% render 'image-url', img: media, size: 800, orientation: block.settings.img_orientation, loading: media_loading, class: '' %}
                {% when 'video' %}
                  {{ media | video_tag: controls: true, image_size: '800x', loading: media_loading, class: 'bg-black w-100' }}
              {% endcase %}
            </div>
          {% endfor %}
        </div>
        <div class="swiper-controls">
          <div class="swiper-pagination"></div>
          <div class="swiper-scrollbar"></div>
          <div class="swiper-button-prev">
            {% render 'svg-icons', icon: 'chevron-left', size: 24 %}
          </div>
          <div class="swiper-button-next">
            {% render 'svg-icons', icon: 'chevron-right', size: 24 %}
          </div>
        </div>
      </div>
    </div>
    <div 
      class="swiper-thumbs swiper mt-4" 
      data-show-thumbs="{{ block.settings.show_thumbs }}"
      data-controls-color="{{ block.settings.controls_color }}"
      {% if product.media.size < 2 %}hidden{% endif %}>
      <div class="swiper-wrapper">
        {% for media in product.media %}
          <div class="swiper-slide" data-media-type="{{ media.media_type }}">
            {% case media.media_type %}
              {% when 'image' %}
                {% render 'image-url', img: media, size: 800, orientation: settings.product_img_orientation, class: 'img-thumbnail' %}
              {% when 'video' %}
                {% render 'svg-icons', icon: 'play', size: '18', aria-hidden: 'true' %}
                {% render 'image-url', img: media.preview_image, size: 800, orientation: settings.product_img_orientation, class: 'img-thumbnail' %}
            {% endcase %}
          </div>
        {% endfor %}
      </div>
    </div>
  </product-media-gallery>
{% endif %}

{% if cart.items == empty %}
  <div class="cart-empty pt-10 pb-12 text-center">
    {% render 'svg-icons', icon: 'cart', class: 'mb-3' %}
    {{ 'cart.empty_html' | t }} 
    <button class="btn btn-outline-primary" type="button" data-bs-dismiss="offcanvas">
      {{ 'cart.continue_shopping' | t }}
    </button>
  </div>
{% else %}
  <ul 
    class="cart-items-list list-unstyled mb-6 border-bottom-1" 
    aria-label="{{ 'general.accessibility.cart_items' | t }}">
    {% for line_item in cart.items %}
      <li class="cart-item py-3">
        <div class="row mx-n3 align-items-center">
          <div class="col-6 px-3">
            <a href="{{ line_item.url }}" tabindex="-1">
              {% render 'image-url', img: line_item.image, orientation: settings.product_card_img_orientation, class: settings.product_card_img_border %}
            </a>
          </div>
          <div class="col-12 px-3 position-relative">
            <div class="me-10">
              <h3 class="cart-item-product-title h6 mb-1">
                <a href="{{ line_item.url }}" class="link-dark text-decoration-none">
                  {{ line_item.product.title }}
                </a>
              </h3>
              {% unless line_item.product.has_only_default_variant %}
                <p class="cart-item-variant-title d-block opacity-70 mb-1 small">
                  {{ line_item.variant.title }}
                </p>
              {% endunless %}
              {% unless line_item.selling_plan_allocation == empty %}
                <p class="cart-item-selling-plan d-block opacity-70 mb-1 small">
                  {{ line_item.selling_plan_allocation.selling_plan.name }}
                </p>
              {% endunless %}
              {% unless line_item.properties == empty %}
                <ul class="cart-item-properties list-unstyled opacity-70 small mb-1">
                  {% for property in line_item.properties %}
                    {% assign first_character_in_key = property.first | slice: 0 %}
                    {% unless first_character_in_key == '_' %}
                      <li>
                        {% if property.last contains 'https' %}
                          {{ property.first }}: 
                          <a href="{{ property.last }}" target="_blank">
                            {{ 'cart.property_view_file' | t }}
                          </a>
                        {% else %}
                          {{ property.first }}: {{ property.last }}
                        {% endif %}
                      </li>
                    {% endunless %}
                  {% endfor %}
                </ul>
              {% endunless %}
              {% if line_item.line_level_discount_allocations.size > 0 %}
                <ul 
                  class="cart-item-discounts list-unstyled fs-xs mb-1 alert alert-primary py-2 px-3" 
                  aria-label="{{ 'cart.applied_discounts' | t }}">
                  {%- for discount in line_item.line_level_discount_allocations -%}
                    <li class="">
                      {% render 'svg-icons', icon: 'tag', size: 12, class: 'me-1' %}
                      {{ discount.discount_application.title }}
                    </li>
                  {%- endfor -%}
                </ul>
              {% endif %}
            </div>
            <div class="d-flex align-items-center justify-content-between pt-4">
              <div class="qty-input-wrapper me-3" role="group" aria-label="{{ 'general.accessibility.quantity' | t }}">
                <button 
                  class="btn btn-qty-minus"
                  type="button"
                  onclick="--this.nextElementSibling.value, this.nextElementSibling.dispatchEvent(new Event('change'))" 
                  aria-label="{{ 'general.accessibility.decrease_qty' | t }}">
                  {% render 'svg-icons', icon: 'minus', size: 14 %}
                </button>
                <input
                  class="form-control form-control-sm" 
                  name="updates[]"
                  type="number"
                  value="{{ line_item.quantity }}"
                  min="0"
                  aria-label="{{ 'product.quantity' | t }}"
                  data-line-item-key="{{ line_item.key }}">
                <button 
                  class="btn btn-qty-plus"
                  type="button"
                  onclick="++this.previousElementSibling.value, this.previousElementSibling.dispatchEvent(new Event('change'))" 
                  aria-label="{{ 'general.accessibility.increase_qty' | t }}">
                  {% render 'svg-icons', icon: 'plus', size: 14 %}
                </button>
              </div>
              <p class="cart-item-price text-end lh-sm mb-0">
                {% if line_item.original_line_price > line_item.final_line_price %}
                  <s class="product-price-compare small opacity-70 me-2">
                    {{ line_item.original_line_price | money }}
                  </s>
                {% endif %}
                <span class="cart-item-price-final">
                  {{ line_item.final_line_price | money }}
                </span>
              </p> 
            </div>
            <button 
              class="btn btn-line-item-remove btn-icon position-absolute top-0 end-0 mt-n4 me-n1"
              type="button"
              data-line-item-key="{{ line_item.key }}"
              aria-label="{{ 'general.accessibility.remove' | t }}">
              {% render 'svg-icons', icon: 'remove', size: 16 %}
            </button>
          </div>
        </div>
      </li>
    {% endfor %}
  </ul>
{% endif %}

{% comment %}
  Renders a different SVG icon based on https://iconsvg.xyz

  Accepts:
  - icon: {String} The icon name, e.g. cart, account, search
  - size: {Number} (Optional) The icon size (default is 22)
  - stroke_width: {Number} (Optional) The icon stroke width (default is 2)
  - class: {String} (Optional) An optional class to apply to the SVG element

  Usage:
  {% render 'svg-icons' icon: 'menu', size: 24, stroke_width: 2, class: "m-3"  %}
{% endcomment %}

<svg 
  xmlns="http://www.w3.org/2000/svg" 
  width="{{ size | default: 22 }}" 
  height="{{ size | default: 22 }}" 
  class="{{ 'svg-icon-' | append: icon }} {{ class }}"
  viewBox="0 0 24 24" 
  fill="none" 
  stroke="currentColor" 
  stroke-width="{{ stroke_width | default: 2 }}" 
  stroke-linecap="round" 
  stroke-linejoin="round">
  {% case icon %}
    {% when 'cart' %}
      {% if settings.cart_icon == 'cart' %}
        <circle cx="10" cy="20.5" r="1"/><circle cx="18" cy="20.5" r="1"/><path d="M2.5 2.5h3l2.7 12.4a2 2 0 0 0 2 1.6h7.7a2 2 0 0 0 2-1.6l1.6-8.4H7.1"/>
      {% elsif settings.cart_icon == 'bag' %}
        <path d="M6 2L3 6v14c0 1.1.9 2 2 2h14a2 2 0 0 0 2-2V6l-3-4H6zM3.8 6h16.4M16 10a4 4 0 1 1-8 0"/>
      {% endif %}
    {% when 'menu' %}
      <line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line>
    {% when 'account' %}
    <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"></path><circle cx="12" cy="7" r="4"></circle>
    {% when 'search' %}
      <circle cx="11" cy="11" r="8"></circle><line x1="21" y1="21" x2="16.65" y2="16.65"></line>
    {% when 'heart' %}
      <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>
    {% when 'recently-viewed' %}
      <path d="M2.5 2v6h6M2.66 15.57a10 10 0 1 0 .57-8.38"/>
    {% when 'x' %}
      <line x1="18" y1="6" x2="6" y2="18"></line><line x1="6" y1="6" x2="18" y2="18"></line>
    {% when 'more' %}
      <circle cx="12" cy="12" r="1"></circle><circle cx="12" cy="5" r="1"></circle><circle cx="12" cy="19" r="1"></circle>
    {% when 'minus' %}
      <line x1="5" y1="12" x2="19" y2="12"></line>
    {% when 'plus' %}
      <line x1="12" y1="5" x2="12" y2="19"></line><line x1="5" y1="12" x2="19" y2="12"></line>
    {% when 'alert-circle' %}
      <circle cx="12" cy="12" r="10"></circle><line x1="12" y1="8" x2="12" y2="12"></line><line x1="12" y1="16" x2="12.01" y2="16"></line>
    {% when 'remove' %}
      <polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path><line x1="10" y1="11" x2="10" y2="17"></line><line x1="14" y1="11" x2="14" y2="17"></line>
    {% when 'lock' %}
      <rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path>
    {% when 'truck' %}
      <rect x="1" y="3" width="15" height="13"></rect><polygon points="16 8 20 8 23 11 23 16 16 16 16 8"></polygon><circle cx="5.5" cy="18.5" r="2.5"></circle><circle cx="18.5" cy="18.5" r="2.5"></circle>
    {% when 'gift' %}
      <polyline points="20 12 20 22 4 22 4 12"></polyline><rect x="2" y="7" width="20" height="5"></rect><line x1="12" y1="22" x2="12" y2="7"></line><path d="M12 7H7.5a2.5 2.5 0 0 1 0-5C11 2 12 7 12 7z"></path><path d="M12 7h4.5a2.5 2.5 0 0 0 0-5C13 2 12 7 12 7z"></path>
    {% when 'maximize' %}
      <path d="M8 3H5a2 2 0 0 0-2 2v3m18 0V5a2 2 0 0 0-2-2h-3m0 18h3a2 2 0 0 0 2-2v-3M3 16v3a2 2 0 0 0 2 2h3"></path>
    {% when 'arrow-top' %}
      <path d="M12 19V6M5 12l7-7 7 7"/>
    {% when 'arrow-bottom' %}
      <path d="M12 5v13M5 12l7 7 7-7"/>
    {% when 'arrow-left' %}
      <path d="M19 12H6M12 5l-7 7 7 7"/>
    {% when 'arrow-right' %}
      <path d="M5 12h13M12 5l7 7-7 7"/>
    {%  when 'chevron-left' %}
      <path d="M15 18l-6-6 6-6"/>
    {%  when 'chevron-right' %}
      <path d="M9 18l6-6-6-6"/>
    {%  when 'chevron-up' %}
      <path d="M18 15l-6-6-6 6"/>
    {%  when 'chevron-down' %}
      <path d="M6 9l6 6 6-6"/>
    {% when 'filter' %}
      <line x1="4" y1="21" x2="4" y2="14"></line><line x1="4" y1="10" x2="4" y2="3"></line><line x1="12" y1="21" x2="12" y2="12"></line><line x1="12" y1="8" x2="12" y2="3"></line><line x1="20" y1="21" x2="20" y2="16"></line><line x1="20" y1="12" x2="20" y2="3"></line><line x1="1" y1="14" x2="7" y2="14"></line><line x1="9" y1="8" x2="15" y2="8"></line><line x1="17" y1="16" x2="23" y2="16"></line>
    {% when 'tag' %}
      <path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"></path><line x1="7" y1="7" x2="7.01" y2="7"></line>
    {% when 'mail' %}
      <path d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"></path><polyline points="22,6 12,13 2,6"></polyline>
    {% when 'star' %}
      <polygon points="12 2 15.09 8.26 22 9.27 17 14.14 18.18 21.02 12 17.77 5.82 21.02 7 14.14 2 9.27 8.91 8.26 12 2"></polygon>
    {% when 'play' %}
      <polygon points="5 3 19 12 5 21 5 3" fill="currentColor"></polygon>
    {% when 'phone' %}
      <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"></path>
    {% when 'edit' %}
      <path d="M20 14.66V20a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h5.34"></path><polygon points="18 2 22 6 12 16 8 16 8 12 18 2"></polygon>
    {% when 'time' %}
      <circle cx="12" cy="12" r="10"></circle><polyline points="12 6 12 12 16 14"></polyline>
  {% endcase %}
</svg>

{% liquid 
  # This section is needed to dynamically fetch it using Shopify's
  # "Bundled section rendering" mode after the cart has been updated.
  # https://shopify.dev/docs/api/ajax/reference/cart#bundled-section-rendering
%}
{% render 'offcanvas-cart' %}

{% liquid 
  # This section is needed to dynamically fetch it using Shopify's
  # "Bundled section rendering" mode after the cart has been updated.
  # https://www.shopify.dev/docs/api/ajax/reference/cart#bundled-section-rendering
%}
{% render 'cart-count-badge' %}

{% liquid
  if shop.permanent_domain contains 'ks-'
    assign limit = 16
  else
    assign limit = section.settings.limit
  endif
%}

<section 
  id="collection-products-{{ collection.id }}" 
  class="
    collection-products
    {{ section.settings.bg_color }} 
    {{ section.settings.bg_gradient }}
    {{ section.settings.text_color }}
    {{ section.settings.border_top_width | prepend: 'border-top-' }}
    {{ section.settings.border_bottom_width | prepend: 'border-bottom-' }}
    {{ section.settings.border_color }} 
    {{ section.settings.pt | prepend: 'pt-' }} 
    {{ section.settings.pb | prepend: 'pb-' }}
  "
  style="
    --bs-bg-opacity: {{ section.settings.bg_opacity | append: '%' }};
    --bs-border-opacity: {{ section.settings.border_opacity | append: '%' }};
  ">
  <div 
    class="container"
    style="max-width: {{ section.settings.container_max_width | append: 'px' }};">
    {% paginate collection.products by limit %}
      {% if collection.products.size == 0 %}
        <p class="alert alert-primary">
          {{ 'collection.empty_html' | t }}
        </p>
      {% else %}
        {% render 'collection-utilities' %}
        <div 
          class="
            product-list mx-n4 mx-desktop-n5 mb-0 row 
            {{ section.settings.breakpoint_mobile | prepend: 'row-cols-' }}
            {{ section.settings.breakpoint_tablet | prepend: 'row-cols-tablet-' }}
            {{ section.settings.breakpoint_desktop | prepend: 'row-cols-desktop-' }}
          " 
          role="list">
          {% for product in collection.products %}
            <div class="p-4 p-desktop-5 mb-4 mb-desktop-5" role="list-item">
              {% render 'product-card', product: product %}
            </div>
          {% endfor %}
        </div>
        <collection-pagination class="collection-pagination"> 
          {% render 'pagination', paginate: paginate %}
        </collection-pagination>
      {% endif %}
    {% endpaginate %}
  </div>
</section>

{% if section.settings.show_filters %}
  {% render 'collection-filters' %}
{% endif %}

{% schema %}
{
  "name": "Collection products",
  "settings": [
    {
      "type": "header",
      "content": "Styling"
    },
    {
      "type": "select",
      "id": "bg_color",
      "label": "Background color",
      "default": "bg-body",
      "options": [
        { "value": "bg-primary", "label": "Primary" },
        { "value": "bg-secondary", "label": "Secondary" },
        { "value": "bg-body", "label": "Body" },
        { "value": "bg-white", "label": "White" }
      ]
    },
    {
      "type": "range",
      "id": "bg_opacity",
      "label": "Background opacity",
      "min": 0,
      "max": 100,
      "step": 1,
      "default": 100,
      "unit": "%"
    },
    {
      "type": "select",
      "id": "bg_gradient",
      "label": "Background gradient",
      "options": [
        { "value": "bg-gradient", "label": "Yes" },
        { "value": "", "label": "No" }
      ],
      "default": ""
    },
    {
      "type": "select",
      "id": "text_color",
      "label": "Text color",
      "default": "text-body",
      "options": [
        { "value": "text-primary", "label": "Primary" },
        { "value": "text-secondary", "label": "Secondary" },
        { "value": "text-body", "label": "Body" },
        { "value": "text-white", "label": "White" }
      ]
    },
    {
      "type": "range",
      "id": "border_top_width",
      "label": "Border top width",
      "default": 0,
      "min": 0,
