      "positional": false,
      "required": false,
      "types": [
        "string"
      ]
    }
  ],
  "summary": "Splits an array's items across multiple pages.",
  "name": "paginate",
  "syntax": "{% paginate array by page_size %}\n  {% for item in array %}\n    forloop_content\n  {% endfor %}\n{% endpaginate %}",
  "syntax_keywords": [
    {
      "keyword": "array",
      "description": "The array to be looped over."
